from typing import Optional, Protocol
from uuid import UUID


class IPostsCacheRepository(Protocol):
    async def get_post(self, post_id: UUID) -> Optional[dict]: ...

    async def set_post(self, post_id: UUID, post_data: dict) -> None: ...

    async def delete_post(self, post_id: UUID) -> None: ...

    async def increment_hits(self, post_id: UUID) -> int: ...

    async def get_hits(self, post_id: UUID) -> int: ...
